var execAsync2 = promisify(exec);
async function isDockerRunning() {
  try {
    await execAsync2("docker info");
    return true;
  } catch {
    return false;
  }
}
async function startPackage(packageName) {
  try {
    const config = await getConfigValue();
    if (!config._packagesDir) {
      throw new Error("Packages directory not configured");
    }
    const composeFile = path18.join(config._packagesDir, packageName, "docker-compose.yml");
    try {
      await fs16.access(composeFile);
    } catch {
      return {
        success: false,
        message: `No docker-compose.yml found for package ${packageName}`
      };
    }
    logger.info(`Starting ${packageName}...`);
    try {
      await execAsync2(`docker compose -f "${composeFile}" pull`, {
        timeout: 12e4
      });
    } catch (error) {
      logger.warn(`Warning: Could not pull latest images, using local: ${error}`);
    }
    const { stdout, stderr } = await execAsync2(
      `docker compose -f "${composeFile}" up -d`,
      { timeout: 12e4 }
    );
    if (stderr && !stderr.includes("Pulling") && !stderr.includes("Pulled")) {
      logger.debug("Docker output:", stderr);
    }
    await waitForHealthy(packageName, composeFile);
    return { success: true, message: `Package ${packageName} started successfully` };
  } catch (error) {
    return {
      success: false,
      message: `Failed to start ${packageName}: ${error.message}`
    };
  }
}
async function stopPackage(packageName) {
  try {
    const config = await getConfigValue();
    if (!config._packagesDir) {
      throw new Error("Packages directory not configured");
    }
    const composeFile = path18.join(config._packagesDir, packageName, "docker-compose.yml");
    try {
      await fs16.access(composeFile);
    } catch {
      return {
        success: false,
        message: `No docker-compose.yml found for package ${packageName}`
      };
    }
    logger.info(`Stopping ${packageName}...`);
    const { stdout, stderr } = await execAsync2(
      `docker compose -f "${composeFile}" down`,
      { timeout: 6e4 }
    );
    return { success: true, message: `Package ${packageName} stopped successfully` };
  } catch (error) {
    return {
      success: false,
      message: `Failed to stop ${packageName}: ${error.message}`
    };
  }
}
async function getPackageStatus(packageName) {
  try {
    const config = await getConfigValue();
    if (!config._packagesDir) {
      throw new Error("Packages directory not configured");
    }
    const composeFile = path18.join(config._packagesDir, packageName, "docker-compose.yml");
    try {
      await fs16.access(composeFile);
    } catch {
      return { running: false, containers: [], message: "Package not installed" };
    }
    const { stdout } = await execAsync2(
      `docker compose -f "${composeFile}" ps --format json`,
      { timeout: 1e4 }
    );
    if (!stdout.trim()) {
      return { running: false, containers: [] };
    }
    const lines = stdout.trim().split("\n").filter((l) => l.trim());
    const containers = [];
    for (const line of lines) {
      try {
        const info = JSON.parse(line);
        containers.push({
          id: info.ID || info.id || "",
          name: info.Name || info.name || "",
          image: info.Image || info.image || "",
          status: mapStatus(info.State || info.state || ""),
          ports: parsePorts(info.Publishers || info.ports || []),
          health: info.Health || info.health || "none",
          created: info.CreatedAt || info.created || ""
        });
      } catch {
      }
    }
    const running = containers.some((c) => c.status === "running");
    return { running, containers };
  } catch (error) {
    return {
      running: false,
      containers: [],
      message: error.message
    };
  }
}
function mapStatus(dockerStatus) {
  const status = dockerStatus.toLowerCase();
  if (status.includes("running")) return "running";
  if (status.includes("paused")) return "paused";
  if (status.includes("restarting")) return "restarting";
  if (status.includes("exited")) return "exited";
  return "stopped";
}
function parsePorts(publishers) {
  if (!Array.isArray(publishers)) return [];
  return publishers.map((p) => `${p.PrivatePort}:${p.PublicPort}/${p.Type}`);
}
async function waitForHealthy(packageName, composeFile, timeout = 12e4) {
  const startTime = Date.now();
  const checkInterval = 2e3;
  while (Date.now() - startTime < timeout) {
    try {
      const { stdout } = await execAsync2(
        `docker compose -f "${composeFile}" ps --format json`,
        { timeout: 5e3 }
      );
      const lines = stdout.trim().split("\n").filter((l) => l.trim());
      const containers = lines.map((line) => {
        try {
          return JSON.parse(line);
        } catch {
          return null;
        }
      }).filter(Boolean);
      const allRunning = containers.every(
        (c) => c.State === "running" || c.state === "running"
      );
      if (allRunning && containers.length > 0) {
        return;
      }
    } catch {
    }
    await new Promise((resolve) => setTimeout(resolve, checkInterval));
  }
  throw new Error(`Timeout waiting for ${packageName} containers to be healthy`);
}
async function getDockerInfo() {
  try {
    const { stdout: version } = await execAsync2('docker version --format "{{.Server.Version}}"');
    const { stdout: info } = await execAsync2('docker info --format "{{json .}}"');
    const data = JSON.parse(info);
    return {
      version: version.trim(),
      running: true,
      containers: {
        total: data.Containers || 0,
        running: data.ContainersRunning || 0,
        paused: data.ContainersPaused || 0,
        stopped: data.ContainersStopped || 0
      },
      images: data.Images || 0
    };
  } catch {
    return {
      version: "unknown",
      running: false,
      containers: { total: 0, running: 0, paused: 0, stopped: 0 },
      images: 0
    };
  }
}
function statusCommand(program2) {
  program2.command("status [package-name]").description("Check hearth and package status").option("-j, --json", "Output as JSON").option("-w, --watch", "Watch mode - continuously update").option("-v, --verbose", "Show detailed information").action(async (packageName, options) => {
    try {
      if (options.watch) {
        await watchStatus(packageName, options);
      } else {
        await showStatus(packageName, options);
      }
    } catch (error) {
      logger.error(`Failed to get status: ${error.message}`);
      process.exit(1);
    }
  });
}
async function showStatus(packageName, options) {
  const config = await getConfigValue();
  const hearthId = config.hearth?.name || "unknown";
  const dockerInfo = await getDockerInfo();
  const dockerRunning = dockerInfo.running;
  const hearthStatus = {
    hearthId,
    hostname: config.hearth?.name || "Unknown",
    role: config.hearth?.role || "primary",
    health: dockerRunning ? "healthy" : "degraded",
    lastHeartbeat: (/* @__PURE__ */ new Date()).toISOString(),
    docker: dockerRunning ? "connected" : "not available",
    resources: dockerRunning ? {
      containers: dockerInfo.containers,
      images: dockerInfo.images
    } : null
  };
  if (options.json) {
    const packages2 = await getAllPackageStatuses(config);
    console.log(JSON.stringify({ ...hearthStatus, packages: packages2 }, null, 2));
    return;
  }
  logger.header("HEARTH STATUS");
  logger.info(`ID: ${chalk15.cyan(hearthStatus.hearthId)}`);
  logger.info(`Hostname: ${chalk15.cyan(hearthStatus.hostname)}`);
  logger.info(`Role: ${chalk15.cyan(hearthStatus.role)}`);
  logger.info(`Health: ${formatHealth(hearthStatus.health)}`);
  logger.info(`Docker: ${dockerRunning ? chalk15.green("connected") : chalk15.red("not available")}`);
  if (options.verbose && dockerRunning) {
    logger.newline();
    logger.section("Docker Resources");
    logger.info(`Containers: ${chalk15.cyan(`${dockerInfo.containers.running} running / ${dockerInfo.containers.total} total`)}`);
    logger.info(`Images: ${chalk15.cyan(dockerInfo.images)}`);
  }
  logger.newline();
  logger.header("PACKAGES");
  const packages = await getAllPackageStatuses(config);
  if (packages.length === 0) {
    logger.info("No packages configured.");
    logger.info(chalk15.dim('Use "hestia add <package>" to add packages.'));
    return;
  }
  if (packageName) {
    const pkg = packages.find((p) => p.name === packageName);
    if (!pkg) {
      logger.error(`Package '${packageName}' not found`);
      process.exit(1);
    }
    displayPackageDetails(pkg, options.verbose || false);
  } else {
    const tableData = packages.map((pkg) => ({
      NAME: pkg.name,
      VERSION: pkg.version,
      STATUS: formatStatus(pkg.running ? "running" : "stopped"),
      TYPE: "docker",
      HEALTH: formatHealth(pkg.health)
    }));
    table(tableData);
    if (options.verbose) {
      logger.newline();
      for (const pkg of packages) {
        displayPackageDetails(pkg, true);
        logger.newline();
      }
    }
  }
}
async function getAllPackageStatuses(config) {
  const packages = Object.entries(config.packages || {}).map(([name, p]) => ({ name, config: p }));
  const statuses = await Promise.all(
    packages.map(async ({ name, config: pkgConfig }) => {
      const status = await getPackageStatus(name);
      return {
        name,
        version: pkgConfig?.version || "latest",
        status: status.running ? "running" : "stopped",
        running: status.running,
        health: status.running ? "healthy" : "unknown",
        containers: status.containers
      };
    })
  );
  return statuses;
}
async function watchStatus(packageName, options) {
  const interval = 2e3;
  logger.info(`Watching status (press Ctrl+C to exit)...
`);
  const run = async () => {
    process.stdout.write("\x1Bc");
    try {
      await showStatus(packageName, { ...options, json: false });
    } catch (error) {
      logger.error("Failed to fetch status");
    }
    logger.newline();
    logger.info(chalk15.gray(`Last updated: ${(/* @__PURE__ */ new Date()).toLocaleTimeString()}`));
    logger.info(chalk15.gray("Press Ctrl+C to exit"));
  };
  await run();
  const timer = setInterval(run, interval);
  process.on("SIGINT", () => {
    clearInterval(timer);
    logger.newline();
    logger.info("Stopped watching");
    process.exit(0);
  });
}
function displayPackageDetails(pkg, verbose) {
  logger.section(pkg.name);
  logger.info(`Version: ${chalk15.cyan(pkg.version)}`);
  logger.info(`Status: ${formatStatus(pkg.running ? "running" : "stopped")}`);
  logger.info(`Type: ${chalk15.cyan("docker")}`);
  logger.info(`Health: ${formatHealth(pkg.health)}`);
  if (verbose && pkg.containers && pkg.containers.length > 0) {
    logger.newline();
    logger.info(chalk15.dim("Containers:"));
    pkg.containers.forEach((container) => {
      logger.info(`  ${chalk15.cyan(container.name)}: ${formatStatus(container.status)}`);
      if (container.ports && container.ports.length > 0) {
        logger.info(`    Ports: ${container.ports.join(", ")}`);
      }
    });
  }
}
function formatStatus(status) {
  const colors = {
    running: (s) => chalk15.green(s),
    stopped: (s) => chalk15.gray(s),
    error: (s) => chalk15.red(s),
    pending: (s) => chalk15.yellow(s),
    installing: (s) => chalk15.blue(s),
    unknown: (s) => chalk15.gray(s)
  };
  return (colors[status] || colors.unknown)(status);
}
function formatHealth(health) {
  const colors = {
    healthy: (s) => chalk15.green("\u2713 " + s),
    degraded: (s) => chalk15.yellow("\u26A0 " + s),
    unhealthy: (s) => chalk15.red("\u2717 " + s),
    unknown: (s) => chalk15.gray("? " + s)
  };
  return (colors[health] || colors.unknown)(health);
}

