init_preflight();
function igniteCommand(program2) {
  program2.command("ignite [packages...]").description("Start all or specific packages (like docker compose up)").option("-v, --verbose", "Show detailed output").option("-p, --parallel", "Start packages in parallel").option("-r, --retries <number>", "Number of retry attempts", "3").action(async (packageNames, options) => {
    try {
      logger.header("PRE-FLIGHT CHECKS");
      const check = await preFlightCheck({
        docker: true,
        config: true,
        writeAccess: true
      });
      if (!check.ok) {
        logger.error("Pre-flight checks failed:");
        check.errors.forEach((e) => logger.error(`  \u2717 ${e}`));
        process.exit(1);
      }
      check.warnings.forEach((w) => logger.warn(`  \u26A0 ${w}`));
      logger.success("All pre-flight checks passed\n");
      const config = await getConfigValue();
      const baseUrl = config.connectors?.controlPlane?.url || "http://localhost:4000";
      const _apiKey = await getCredential("apiKey") || "";
      logger.header("IGNITING HEARTH");
      logger.info(`Target: ${chalk15.cyan(config.hearth.name || "local")}`);
      logger.info(`Docker: ${chalk15.cyan(await isDockerRunning() ? "connected" : "not available")}`);
      logger.newline();
      const allPackages = Object.entries(config.packages || {}).filter(([_, p]) => p.enabled !== false).map(([name, p]) => ({
        name,
        status: p.status || "stopped",
        type: p.type || "docker"
      }));
      if (allPackages.length === 0) {
        logger.warn('No packages configured. Use "hestia add <package>" to add packages.');
        process.exit(0);
      }
      const targetPackages = packageNames.length > 0 ? allPackages.filter((p) => packageNames.includes(p.name)) : allPackages;
      if (targetPackages.length === 0) {
        if (packageNames.length > 0) {
          logger.error(`Specified packages not found: ${packageNames.join(", ")}`);
          process.exit(1);
        }
      }
      logger.info("Checking current status...");
      const packagesWithStatus = await Promise.all(
        targetPackages.map(async (pkg) => {
          const status = await getPackageStatus(pkg.name);
          return { ...pkg, ...status };
        })
      );
      const toStart = packagesWithStatus.filter((p) => !p.running);
      const alreadyRunning = packagesWithStatus.filter((p) => p.running);
      if (alreadyRunning.length > 0) {
        logger.info(`Already running: ${alreadyRunning.map((p) => chalk15.cyan(p.name)).join(", ")}`);
      }
      if (toStart.length === 0) {
        logger.success("\nAll packages are already running!");
        return;
      }
      logger.info(`
Packages to ignite: ${toStart.map((p) => chalk15.cyan(p.name)).join(", ")}`);
      logger.newline();
      const tasks = toStart.map((pkg) => ({
        title: `Starting ${pkg.name}`,
        task: async (ctx) => {
          const retries = parseInt(options.retries?.toString() || "3", 10);
          let lastError = null;
          for (let attempt = 1; attempt <= retries; attempt++) {
            try {
              logger.debug(`Attempt ${attempt}/${retries} for ${pkg.name}`);
              const result = await startPackage(pkg.name);
              if (result.success) {
                ctx[`${pkg.name}_started`] = true;
                logger.success(`  \u2713 ${pkg.name} started successfully`);
                return;
              } else {
                throw new Error(result.message);
              }
            } catch (error) {
              lastError = error;
              logger.warn(`  Attempt ${attempt} failed: ${error.message}`);
              if (attempt < retries) {
                const delay = 2e3 * attempt;
                logger.info(`  Retrying in ${delay}ms...`);
                await sleep(delay);
              }
            }
          }
          throw lastError || new Error(`Failed to start ${pkg.name} after ${retries} attempts`);
        },
        skip: () => pkg.running
      }));
      if (options.parallel) {
        logger.info("Starting packages in parallel...\n");
        await Promise.all(tasks.map((t) => t.task({})));
      } else {
        await runTasks(tasks, {
          concurrent: false,
          exitOnError: true,
          renderer: options.verbose ? "verbose" : "default"
        });
      }
      logger.newline();
      logger.success("\u2728 Hearth ignited successfully!");
      logger.info(`
${chalk15.dim('Use "hestia status" to check service status')}`);
    } catch (error) {
      logger.error(`Failed to ignite: ${error.message}`);
      if (options.verbose) {
        console.error(error);
      }
      process.exit(1);
    }
  });
}
function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

// src/commands/extinguish.ts
init_esm_shims();
init_utils();
init_utils();
init_preflight();
function extinguishCommand(program2) {
  program2.command("extinguish [packages...]").description("Stop all or specific packages (like docker compose down)").option("-v, --verbose", "Show detailed output").option("-f, --force", "Force stop without confirmation").option("-p, --parallel", "Stop packages in parallel").option("-a, --all", "Stop all packages including core services").action(async (packageNames, options) => {
    try {
      logger.header("PRE-FLIGHT CHECKS");
      const check = await preFlightCheck({
        docker: true,
        config: true
      });
      if (!check.ok) {
        logger.error("Pre-flight checks failed:");
        check.errors.forEach((e) => logger.error(`  \u2717 ${e}`));
        process.exit(1);
      }
      logger.success("All pre-flight checks passed\n");
      const config = await getConfigValue();
      const _apiKey = await getCredential("apiKey") || "";
      logger.header("EXTINGUISHING HEARTH");
      logger.info(`Target: ${chalk15.cyan(config.hearth.name || "local")}`);
      logger.newline();
      const allPackages = Object.entries(config.packages || {}).filter(([_, p]) => p.enabled !== false).map(([name]) => ({ name }));
      if (allPackages.length === 0) {
        logger.warn("No packages configured.");
        process.exit(0);
      }
      logger.info("Checking current status...");
      const packagesWithStatus = await Promise.all(
        allPackages.map(async (pkg) => {
          const status = await getPackageStatus(pkg.name);
          return { ...pkg, ...status };
        })
      );
      let targetPackages = packageNames.length > 0 ? packagesWithStatus.filter((p) => packageNames.includes(p.name)) : packagesWithStatus.filter((p) => p.running);
      const corePackages = ["synap-backend", "synap-postgres", "synap-redis", "synap-typesense"];
      if (!options.all) {
        targetPackages = targetPackages.filter((p) => !corePackages.includes(p.name));
      }
      if (targetPackages.length === 0) {
        logger.info("No packages to stop");
        return;
      }
      const stoppingCore = targetPackages.some((p) => corePackages.includes(p.name));
      if (stoppingCore && options.all) {
        logger.warn("\u26A0\uFE0F  Stopping core packages may cause data loss!");
        logger.warn("   Core packages: " + corePackages.join(", "));
        logger.newline();
      }
      logger.info(`Packages to extinguish: ${targetPackages.map((p) => chalk15.yellow(p.name)).join(", ")}`);
      logger.newline();
      if (!options.force) {
        const { confirm } = await inquirer10.prompt([{
          type: "confirm",
          name: "confirm",
          message: `Stop ${targetPackages.length} package(s)?`,
          default: false
        }]);
        if (!confirm) {
          logger.info("Operation cancelled.");
          return;
        }
      }
      logger.newline();
      const tasks = targetPackages.map((pkg) => ({
        title: `Stopping ${pkg.name}`,
        task: async (ctx) => {
          try {
            logger.debug(`Stopping ${pkg.name}...`);
            const result = await stopPackage(pkg.name);
            if (result.success) {
              ctx[`${pkg.name}_stopped`] = true;
              logger.success(`  \u2713 ${pkg.name} stopped`);
              return;
            } else {
              throw new Error(result.message);
            }
          } catch (error) {
            if (error.message?.includes("not running") || error.message?.includes("No such container")) {
              ctx[`${pkg.name}_stopped`] = true;
              logger.info(`  \u2139 ${pkg.name} already stopped`);
              return;
            }
            throw error;
          }
        },
        skip: () => !pkg.running
      }));
      const context = await runTasks(tasks, {
        concurrent: options.parallel || false,
        exitOnError: false,
        renderer: options.verbose ? "verbose" : "default"
      });
      logger.newline();
      logger.header("EXTINGUISH SUMMARY");
      let stopped = 0;
      let skipped = 0;
      let failed = 0;
      for (const pkg of targetPackages) {
        const key = `${pkg.name}_stopped`;
        if (context[key]) {
          logger.success(`${pkg.name}: Stopped successfully`);
          stopped++;
        } else if (!pkg.running) {
          logger.info(`${pkg.name}: Already stopped (skipped)`);
          skipped++;
        } else {
          logger.error(`${pkg.name}: Failed to stop`);
          failed++;
        }
      }
      logger.newline();
      logger.info(`Total: ${chalk15.green(stopped + " stopped")}, ${chalk15.gray(skipped + " skipped")}, ${chalk15.red(failed + " failed")}`);
      if (failed > 0) {
        process.exit(1);
      }
      logger.newline();
      logger.success("\u{1F525} Hearth extinguished successfully");
      logger.info(`
${chalk15.dim('Use "hestia ignite" to restart services')}`);
    } catch (error) {
      logger.error(`Failed to extinguish: ${error.message}`);
      if (options.verbose) {
        console.error(error);
      }
      process.exit(1);
    }
  });
}

