function addCommand(program2) {
  program2.command("add <package-name> [version]").description("Add a package to the hearth").option("-c, --config <path>", "Path to package configuration file").option("-s, --source <source>", "Package source (npm, docker, git, binary)").option("-a, --auto-start", "Start package immediately after install").option("-e, --env <vars...>", "Environment variables (KEY=value format)").action(async (packageName, version, options) => {
    try {
      const config = await getConfigValue();
      const baseUrl = config.connectors?.controlPlane?.url || "http://localhost:4000";
      const apiKey = await getCredential("apiKey") || "";
      const _api = { baseUrl, apiKey };
      const pkgService = new PackageService({ config, packagesDir: "/tmp/packages", logger });
      logger.header("ADDING PACKAGE");
      logger.info(`Package: ${chalk15.cyan(packageName)}`);
      logger.info(`Version: ${chalk15.cyan(version || "latest")}`);
      logger.newline();
      const existingPackages = [];
      const existing = existingPackages.find((p) => p.name === packageName);
      if (existing) {
        logger.warn(`Package '${packageName}' is already installed (version ${existing.version})`);
        const { action } = await inquirer10.prompt([{
          type: "list",
          name: "action",
          message: "What would you like to do?",
          choices: [
            { name: "Update to new version", value: "update" },
            { name: "Reinstall current version", value: "reinstall" },
            { name: "Cancel", value: "cancel" }
          ]
        }]);
        if (action === "cancel") {
          logger.info("Add cancelled");
          return;
        }
        if (action === "update" && !version) {
          const { newVersion } = await inquirer10.prompt([{
            type: "input",
            name: "newVersion",
            message: "Enter version to update to:",
            default: "latest"
          }]);
          version = newVersion;
        }
      }
      const packageConfig = {};
      if (options.config) {
        const fs25 = await import('fs/promises');
        const configContent = await fs25.readFile(options.config, "utf-8");
        Object.assign(packageConfig, JSON.parse(configContent));
      }
      const envVars = {};
      if (options.env) {
        for (const env of options.env) {
          const [key, ...valueParts] = env.split("=");
          if (key && valueParts.length > 0) {
            envVars[key] = valueParts.join("=");
          }
        }
      }
      await withSpinner(
        `Installing ${packageName}...`,
        async () => {
          await pkgService.install({
            name: packageName,
            version: version || "latest",
            source: { type: options.source || "npm", url: packageName },
            config: envVars
          });
        },
        `${packageName} installed successfully`
      );
      if (options.autoStart) {
        await withSpinner(
          `Starting ${packageName}...`,
          () => pkgService.start(packageName),
          `${packageName} started`
        );
      }
      logger.newline();
      logger.success(`Package ${packageName} added to hearth! \u{1F4E6}`);
      if (!options.autoStart) {
        logger.info(`Run ${chalk15.cyan(`hestia ignite ${packageName}`)} to start it`);
      }
    } catch (error) {
      logger.error(`Failed to add package: ${error.message}`);
      process.exit(1);
    }
  });
}

// src/commands/remove.ts
init_esm_shims();
init_utils();
init_utils();
init_utils();
function removeCommand(program2) {
  program2.command("remove <package-name>").description("Remove a package from the hearth").option("-f, --force", "Force removal without confirmation").option("-p, --purge", "Remove all package data and configuration").option("-k, --keep-data", "Keep package data volumes").action(async (packageName, options) => {
    try {
      const config = await getConfigValue();
      const baseUrl = config.connectors?.controlPlane?.url || "http://localhost:4000";
      const _apiKey = await getCredential("apiKey") || "";
      const pkgService = new PackageService({ config, packagesDir: "/tmp/packages", logger });
      logger.header("REMOVING PACKAGE");
      logger.info(`Package: ${chalk15.yellow(packageName)}`);
      logger.newline();
      const packages = Object.entries(config.packages).map(([name, p]) => ({ name, version: p.version || "latest", status: p.enabled ? "running" : "stopped" }));
      const pkg = packages.find((p) => p.name === packageName);
      if (!pkg) {
        logger.error(`Package '${packageName}' not found`);
        process.exit(1);
      }
      logger.info(`Current status: ${pkg.status}`);
      logger.info(`Version: ${pkg.version}`);
      logger.newline();
      if (pkg.status === "running" && !options.force) {
        const { stopFirst } = await inquirer10.prompt([{
          type: "confirm",
          name: "stopFirst",
          message: `Package ${packageName} is currently running. Stop it first?`,
          default: true
        }]);
        if (stopFirst) {
          await withSpinner(
            `Stopping ${packageName}...`,
            () => api.stopPackage(packageName),
            `${packageName} stopped`
          );
        } else if (!options.force) {
          logger.error("Cannot remove a running package. Use --force to override.");
          process.exit(1);
        }
      }
      if (!options.force) {
        const warning = options.purge ? `WARNING: This will remove ${packageName} and ALL its data permanently.` : `Remove ${packageName}?`;
        logger.warn(warning);
        logger.newline();
        const { confirm } = await inquirer10.prompt([{
          type: "confirm",
          name: "confirm",
          message: "Are you sure?",
          default: false
        }]);
        if (!confirm) {
          logger.info("Removal cancelled");
          return;
        }
        if (options.purge) {
          const { confirmPurge } = await inquirer10.prompt([{
            type: "input",
            name: "confirmPurge",
            message: `Type "${packageName}" to confirm purge:`
          }]);
          if (confirmPurge !== packageName) {
            logger.error("Confirmation mismatch. Removal cancelled.");
            process.exit(1);
          }
        }
      }
      if (pkg.status === "running" && options.force) {
        await withSpinner(
          `Force stopping ${packageName}...`,
          () => pkgService.stop(packageName),
          `${packageName} stopped`
        );
      }
      await withSpinner(
        "Removing package files...",
        () => pkgService.remove(packageName, options.purge, options.keepData),
        "Package files removed"
      );
      logger.newline();
      logger.success(`Package ${packageName} removed successfully \u{1F5D1}\uFE0F`);
      if (!options.purge && !options.keepData) {
        logger.info(`Data preserved. Use ${chalk15.cyan(`hestia remove ${packageName} --purge`)} to remove all data`);
      }
    } catch (error) {
      logger.error(`Failed to remove package: ${error.message}`);
      process.exit(1);
    }
  });
}

