var execAsync6 = promisify(exec);
function createProgressReporter(spinnerId) {
  spinner.start(spinnerId, "Initializing...");
  return {
    report(message) {
      spinner.update(spinnerId, message);
    },
    onProgress(percent) {
      const currentText = spinner["spinners"]?.get(spinnerId)?.text || "Working...";
      const baseText = currentText.split(" (")[0];
      spinner.update(spinnerId, `${baseText} (${Math.round(percent)}%)`);
    }
  };
}
function installCommand(program2) {
  program2.command("install [phase]").description("Run Hestia installation (phase1, phase2, phase3, or all)").argument("[phase]", "Installation phase", "all").option("-t, --target <path>", "Installation target directory", "/opt/hestia").option("-s, --safe-mode", "Safe mode - preserve existing data").option("-u, --unattended", "Unattended installation (no prompts)").option("--skip <phases...>", "Skip specific phases (comma-separated)").option("--dry-run", "Show what would be done without executing").action(async (phase, options) => {
    try {
      logger.header("HESTIA INSTALLER");
      const validPhases = ["phase1", "phase2", "phase3"];
      const phasesToRun = phase === "all" ? validPhases : [phase];
      if (!validPhases.includes(phasesToRun[0]) && phase !== "all") {
        logger.error(`Invalid phase: ${phase}`);
        logger.info(`Valid phases: ${validPhases.join(", ")}, all`);
        process.exit(1);
      }
      const skipPhases = options.skip ? options.skip.flatMap((s) => s.split(",")) : [];
      const filteredPhases = phasesToRun.filter((p) => !skipPhases.includes(p));
      if (filteredPhases.length === 0) {
        logger.info("All phases skipped. Nothing to do.");
        return;
      }
      logger.info(`Phases to run: ${filteredPhases.map((p) => chalk15.cyan(p)).join(", ")}`);
      logger.info(`Target directory: ${chalk15.cyan(options.target || "/opt/hestia")}`);
      logger.newline();
      if (!options.dryRun) {
        const canProceed = await runPreflightChecks(options);
        if (!canProceed) {
          logger.error("Pre-flight checks failed. Aborting.");
          process.exit(1);
        }
      }
      for (const p of filteredPhases) {
        await runPhase(p, options);
      }
      logger.newline();
      logger.success("Installation complete! \u{1F525}");
      if (phase === "all" || phase === "phase3") {
        logger.newline();
        section("Next Steps");
        logger.info(`1. Initialize Hestia: ${chalk15.cyan("hestia init")}`);
        logger.info(`2. Add packages: ${chalk15.cyan("hestia add <package>")}`);
        logger.info(`3. Ignite hearth: ${chalk15.cyan("hestia ignite")}`);
      }
    } catch (error) {
      logger.error(`Installation failed: ${error.message}`);
      process.exit(1);
    }
  });
}
async function runPhase(phase, options) {
  section(`Running ${phase.toUpperCase()}`);
  if (options.dryRun) {
    logger.info(chalk15.gray("[DRY RUN] Would execute phase"));
    return;
  }
  const spinnerId = `phase-${phase}`;
  const progress = createProgressReporter(spinnerId);
  let result;
  switch (phase) {
    case "phase1": {
      const input = {
        targetDir: options.target || "/opt/hestia",
        safeMode: options.safeMode,
        unattended: options.unattended,
        dryRun: options.dryRun
      };
      result = await runPhase1(input, progress);
      break;
    }
    case "phase2": {
      const input = {
        targetDir: options.target || "/opt/hestia",
        safeMode: options.safeMode,
        unattended: options.unattended,
        dryRun: options.dryRun
      };
      result = await runPhase2(input, progress);
      break;
    }
    case "phase3": {
      const input = {
        targetDir: options.target || "/opt/hestia",
        safeMode: options.safeMode,
        unattended: options.unattended,
        dryRun: options.dryRun
      };
      result = await runPhase3(input, progress);
      break;
    }
    default:
      throw new Error(`Unknown phase: ${phase}`);
  }
  if (result.success) {
    spinner.succeed(spinnerId, `${phase} completed successfully`);
  } else {
    spinner.fail(spinnerId, `${phase} failed: ${result.error}`);
    throw new Error(result.error || `${phase} failed`);
  }
}
async function runPreflightChecks(options) {
  section("Pre-flight Checks");
  const checks = [
    { name: "Root/sudo access", fn: checkSudo },
    { name: "Target directory writable", fn: () => checkDirectory(options.target || "/opt/hestia") },
    { name: "Internet connectivity", fn: checkInternet2 },
    { name: "Docker available", fn: checkDocker2 }
  ];
  let allPassed = true;
  for (const check of checks) {
    spinner.start(`check-${check.name}`, `Checking: ${check.name}`);
    try {
      const passed = await check.fn();
      if (passed) {
        spinner.succeed(`check-${check.name}`, `${check.name}: OK`);
      } else {
        spinner.fail(`check-${check.name}`, `${check.name}: FAILED`);
        allPassed = false;
      }
    } catch (error) {
      spinner.fail(`check-${check.name}`, `${check.name}: ERROR - ${error.message}`);
      allPassed = false;
    }
  }
  logger.newline();
  return allPassed;
}
async function checkSudo() {
  try {
    if (process.getuid && process.getuid() === 0) {
      return true;
    }
    await execAsync6("sudo -n true");
    return true;
  } catch {
    return false;
  }
}
async function checkDirectory(path27) {
  try {
    await execAsync6(`mkdir -p ${path27}`);
    return true;
  } catch {
    return false;
  }
}
async function checkInternet2() {
  try {
    await execAsync6("curl -s --max-time 5 https://cloudflare.com > /dev/null");
    return true;
  } catch {
    return false;
  }
}
async function checkDocker2() {
  try {
    await execAsync6("docker version > /dev/null 2>&1");
    return true;
  } catch {
    return false;
  }
}

