async function detectNetworkType() {
  try {
    const { stdout: publicIP } = await execAsync13(
      'curl -s https://api.ipify.org 2>/dev/null || echo ""',
      { timeout: 5e3 }
    );
    if (!publicIP.trim()) {
      return "unknown";
    }
    const ipParts = publicIP.trim().split(".");
    if (ipParts.length === 4) {
      const first = parseInt(ipParts[0], 10);
      const second = parseInt(ipParts[1], 10);
      if (first === 100 && second >= 64 && second <= 127) {
        return "cgmat";
      }
      if (first === 10 || first === 172 && second >= 16 && second <= 31 || first === 192 && second === 168) {
        return "private";
      }
    }
    return "public";
  } catch {
    return "unknown";
  }
}
