function tunnelCommand(program2) {
  const tunnelCmd = program2.command("tunnel").description("Manage secure remote tunnel access (Pangolin)").configureHelp({
    subcommandTerm: (cmd) => `${cmd.name()}`,
    subcommandDescription: (cmd) => cmd.description()
  }).option("-j, --json", "Output as JSON").action(async (options) => {
    await showTunnelStatus(options);
  });
  tunnelCmd.command("enable").description("Enable and configure remote tunnel access").option("-m, --mode <mode>", "Mode: server (VPS) or client (home)", "client").option("-s, --server <url>", "Server URL (for client mode)").option("-t, --token <token>", "Authentication token (for client mode)").option("-d, --domain <domain>", "Domain for server mode").option("-p, --port <port>", "WireGuard port", "51820").option("-f, --force", "Force reconfiguration").action(async (options) => {
    await enableTunnel(options);
  });
  tunnelCmd.command("disable").description("Disable remote tunnel access").option("-f, --force", "Force without confirmation").action(async (options) => {
    await disableTunnel(options);
  });
  tunnelCmd.command("status").description("Show detailed tunnel status").option("-j, --json", "Output as JSON").option("-v, --verbose", "Show verbose information").action(async (options) => {
    await showDetailedStatus(options);
  });
  tunnelCmd.command("url").description("Show the public tunnel URL").option("-j, --json", "Output as JSON").action(async (options) => {
    await showTunnelUrl(options);
  });
  tunnelCmd.command("logs").description("Show tunnel logs").option("-n, --lines <number>", "Number of lines to show", "100").option("-f, --follow", "Follow log output (live)").action(async (options) => {
    await showTunnelLogs(options);
  });
  tunnelCmd.command("list").alias("ls").description("List active tunnels and endpoints").option("-j, --json", "Output as JSON").action(async (options) => {
    await listTunnels(options);
  });
  tunnelCmd.command("config").description("Update tunnel configuration").option("--add-tunnel <name:port>", "Add a new tunnel (format: name:port)").option("--remove-tunnel <name>", "Remove a tunnel").action(async (options) => {
    await updateTunnelConfig(options);
  });
  tunnelCmd.command("restart").description("Restart tunnel service").action(async () => {
    await restartTunnel();
  });
}
async function showTunnelStatus(options) {
  try {
    const status = await pangolinService.getPangolinStatus();
    const tunnelInfo = await pangolinService.getStatus();
    if (options.json) {
      console.log(JSON.stringify({
        installed: status.installed,
        running: status.running,
        mode: status.mode,
        status: tunnelInfo.status,
        publicUrl: tunnelInfo.publicUrl,
        connectedAt: tunnelInfo.connectedAt,
        activeTunnels: tunnelInfo.activeTunnels
      }, null, 2));
      return;
    }
    if (!status.installed) {
      logger.info(chalk15.yellow("Tunnel not installed"));
      logger.info("Run " + chalk15.cyan("hestia tunnel:enable") + " to set up remote access");
      return;
    }
    logger.header("TUNNEL STATUS");
    const statusIcon = status.running ? tunnelInfo.status === "connected" ? chalk15.green("\u{1F7E2}") : chalk15.yellow("\u{1F7E1}") : chalk15.red("\u{1F534}");
    logger.info(`Status: ${statusIcon} ${formatTunnelStatus(tunnelInfo.status)}`);
    if (status.mode) {
      logger.info(`Mode: ${chalk15.cyan(status.mode.toUpperCase())}`);
    }
    if (status.version && status.version !== "unknown") {
      logger.info(`Version: ${chalk15.gray(status.version)}`);
    }
    if (tunnelInfo.publicUrl) {
      logger.info(`Public URL: ${chalk15.cyan.underline(tunnelInfo.publicUrl)}`);
    }
    if (tunnelInfo.activeTunnels > 0) {
      logger.info(`Active Tunnels: ${chalk15.cyan(tunnelInfo.activeTunnels)}`);
    }
    if (tunnelInfo.connectedAt) {
      logger.info(`Connected: ${chalk15.gray(formatDuration2(Date.now() - tunnelInfo.connectedAt.getTime()))}`);
    }
    if (status.errors.length > 0) {
      logger.newline();
      logger.warn("Issues detected:");
      status.errors.forEach((e) => logger.error(`  \u2022 ${e}`));
    }
    if (!status.running) {
      logger.newline();
      logger.info("To start the tunnel: " + chalk15.cyan("hestia tunnel:enable"));
    }
  } catch (error) {
    logger.error(`Failed to get tunnel status: ${error.message}`);
    process.exit(1);
  }
}
async function enableTunnel(options) {
  try {
    const existingStatus = await pangolinService.getPangolinStatus();
    if (existingStatus.installed && !options.force) {
      const { overwrite } = await inquirer10.prompt([{
        type: "confirm",
        name: "overwrite",
        message: "Tunnel is already configured. Reconfigure?",
        default: false
      }]);
      if (!overwrite) {
        logger.info("Cancelled");
        return;
      }
    }
    let mode = options.mode || "client";
    if (!options.mode) {
      logger.header("TUNNEL SETUP");
      logger.info(chalk15.gray("Pangolin provides secure remote access without third-party dependencies."));
      logger.newline();
      const { selectedMode } = await inquirer10.prompt([{
        type: "list",
        name: "selectedMode",
        message: "Select tunnel mode:",
        choices: [
          {
            name: "SERVER - I have a VPS with public IP (relay server)",
            value: "server",
            short: "Server (VPS)"
          },
          {
            name: "CLIENT - Home server behind CGNAT/firewall",
            value: "client",
            short: "Client (Home)"
          }
        ],
        default: "client"
      }]);
      mode = selectedMode;
    }
    await withSpinner(
      `Installing Pangolin ${mode}...`,
      async () => pangolinService.install(mode),
      `Pangolin installed for ${mode} mode`
    );
    if (mode === "server") {
      await configureServerMode(options);
    } else {
      await configureClientMode(options);
    }
    await withSpinner(
      "Starting tunnel service...",
      async () => pangolinService.start(),
      "Tunnel service started"
    );
    logger.newline();
    logger.success(chalk15.bold("Tunnel configured successfully! \u{1F525}"));
    const tunnelInfo = await pangolinService.getStatus();
    if (tunnelInfo.publicUrl) {
      logger.newline();
      logger.info(`${chalk15.bold("Public URL:")} ${chalk15.cyan.underline(tunnelInfo.publicUrl)}`);
    }
    if (mode === "server") {
      logger.newline();
      section("Next Steps (on your home server)");
      logger.info(`1. Install Hestia on your home server`);
      logger.info(`2. Run: ${chalk15.cyan("hestia tunnel:enable --mode client --server <this-ip>")}`);
      logger.info(`3. Access your home Hestia from anywhere!`);
    } else {
      logger.newline();
      logger.info("Your home server is now accessible remotely!");
      logger.info(`Run ${chalk15.cyan("hestia tunnel:status")} to check connection status`);
    }
  } catch (error) {
    logger.error(`Failed to enable tunnel: ${error.message}`);
    process.exit(1);
  }
}
async function configureServerMode(options) {
  logger.newline();
  logger.header("SERVER CONFIGURATION");
  logger.info(chalk15.gray("This will run Pangolin as a relay server on your VPS."));
  logger.newline();
  let domain = options.domain;
  if (!domain) {
    const { config } = await loadConfig();
    const defaultDomain = config.hearth.domain || "example.com";
    const answers = await inquirer10.prompt([{
      type: "input",
      name: "domain",
      message: "Domain for tunnel access (e.g., tunnel.example.com):",
      default: `tunnel.${defaultDomain}`,
      validate: (input) => input.includes(".") || "Please enter a valid domain"
    }]);
    domain = answers.domain;
  }
  const serverPort = parseInt(options.port || "3000", 10);
  const wireguardPort = 51820;
  const success = pangolinService.configureServer({
    domain,
    baseUrl: `https://${domain}`,
    serverPort,
    wireguardPort
  });
  if (!success) {
    throw new Error("Failed to configure Pangolin server");
  }
  const token = generateSecureToken();
  logger.newline();
  section("Server Configuration Complete");
  logger.success(`Domain: ${chalk15.cyan(domain)}`);
  logger.success(`WireGuard Port: ${chalk15.cyan(wireguardPort)}`);
  logger.newline();
  logger.info(chalk15.bold("Client Registration Token:"));
  logger.info(chalk15.yellow(token));
  logger.newline();
  logger.info(chalk15.gray("Share this token with your home server during client setup."));
}
async function configureClientMode(options) {
  logger.newline();
  logger.header("CLIENT CONFIGURATION");
  logger.info(chalk15.gray("Connect to a Pangolin server to expose your home Hestia."));
  logger.newline();
  const networkType = await detectNetworkType2();
  if (networkType === "cgmat" || networkType === "private") {
    logger.info(chalk15.yellow("\u26A0\uFE0F  CGNAT or private IP detected"));
    logger.info(chalk15.gray("Pangolin is perfect for this setup - no port forwarding needed!"));
    logger.newline();
  }
  let serverUrl = options.server;
  if (!serverUrl) {
    const answers = await inquirer10.prompt([{
      type: "input",
      name: "serverUrl",
      message: "Pangolin Server URL (e.g., https://tunnel.example.com):",
      validate: (input) => input.startsWith("http") || "Please enter a valid URL (https://...)"
    }]);
    serverUrl = answers.serverUrl;
  }
  let token = options.token;
  if (!token) {
    const answers = await inquirer10.prompt([{
      type: "input",
      name: "token",
      message: "Registration token from server:",
      validate: (input) => input.length > 10 || "Please enter a valid token"
    }]);
    token = answers.token;
  }
  if (!token) {
    throw new Error("Token is required");
  }
  const success = pangolinService.configureClient(serverUrl, token);
  if (!success) {
    throw new Error("Failed to configure Pangolin client");
  }
  logger.newline();
  section("Client Configuration Complete");
  logger.success(`Server: ${chalk15.cyan(serverUrl)}`);
}
async function disableTunnel(options) {
  try {
    const status = await pangolinService.getPangolinStatus();
    if (!status.installed) {
      logger.info("Tunnel is not installed");
      return;
    }
    if (!options.force) {
      const { confirm } = await inquirer10.prompt([{
        type: "confirm",
        name: "confirm",
        message: "Disable and remove tunnel access?",
        default: false
      }]);
      if (!confirm) {
        logger.info("Cancelled");
        return;
      }
    }
    await withSpinner(
      "Stopping tunnel service...",
      async () => pangolinService.stop(),
      "Tunnel service stopped"
    );
    await updateConfig({
      tunnel: {
        enabled: false,
        provider: "none"
      }
    });
    logger.success("Tunnel disabled");
  } catch (error) {
    logger.error(`Failed to disable tunnel: ${error.message}`);
    process.exit(1);
  }
}
async function showDetailedStatus(options) {
  try {
    const status = await pangolinService.getPangolinStatus();
    const tunnelInfo = await pangolinService.getStatus();
    const tunnels = await pangolinService.listTunnels();
    if (options.json) {
      console.log(JSON.stringify({
        installed: status.installed,
        running: status.running,
        mode: status.mode,
        version: status.version,
        configValid: status.configValid,
        status: tunnelInfo,
        tunnels,
        errors: status.errors
      }, null, 2));
      return;
    }
    logger.header("TUNNEL DETAILED STATUS");
    section("Installation");
    logger.info(`Installed: ${status.installed ? chalk15.green("Yes") : chalk15.red("No")}`);
    logger.info(`Running: ${status.running ? chalk15.green("Yes") : chalk15.red("No")}`);
    if (status.version) {
      logger.info(`Version: ${chalk15.cyan(status.version)}`);
    }
    if (status.errors.length > 0) {
      logger.newline();
      logger.warn("Configuration Issues:");
      status.errors.forEach((e) => logger.error(`  \u2022 ${e}`));
    }
    if (status.installed) {
      section("Connection");
      logger.info(`Status: ${formatTunnelStatus(tunnelInfo.status)}`);
      if (status.mode) {
        logger.info(`Mode: ${chalk15.cyan(status.mode.toUpperCase())}`);
      }
      if (tunnelInfo.publicUrl) {
        logger.info(`Public URL: ${chalk15.cyan(tunnelInfo.publicUrl)}`);
      }
      if (tunnelInfo.serverUrl) {
        logger.info(`Server: ${chalk15.gray(tunnelInfo.serverUrl)}`);
      }
      if (tunnelInfo.connectedAt) {
        logger.info(`Connected: ${formatDuration2(Date.now() - tunnelInfo.connectedAt.getTime())}`);
      }
      if (tunnelInfo.latency) {
        logger.info(`Latency: ${chalk15.cyan(`${tunnelInfo.latency}ms`)}`);
      }
      if (options.verbose && tunnelInfo.bytesTransferred) {
        logger.info(`Data Sent: ${chalk15.gray(formatBytes6(tunnelInfo.bytesTransferred.sent))}`);
        logger.info(`Data Received: ${chalk15.gray(formatBytes6(tunnelInfo.bytesTransferred.received))}`);
      }
    }
    if (tunnels.length > 0) {
      section("Active Tunnels");
      tunnels.forEach((t) => {
        const statusIcon = t.status === "active" ? chalk15.green("\u25CF") : chalk15.gray("\u25CB");
        logger.info(`${statusIcon} ${chalk15.bold(t.name)}`);
        logger.info(`   Local Port: ${chalk15.cyan(t.localPort)}`);
        if (t.remotePort) {
          logger.info(`   Remote Port: ${chalk15.cyan(t.remotePort)}`);
        }
        if (t.url) {
          logger.info(`   URL: ${chalk15.cyan.underline(t.url)}`);
        }
      });
    }
  } catch (error) {
    logger.error(`Failed to get detailed status: ${error.message}`);
    process.exit(1);
  }
}
async function showTunnelUrl(options) {
  try {
    const url = await pangolinService.getTunnelUrl();
    if (options.json) {
      console.log(JSON.stringify({ publicUrl: url }, null, 2));
      return;
    }
    if (url) {
      console.log(url);
    } else {
      logger.warn("No public URL configured");
      logger.info("Run " + chalk15.cyan("hestia tunnel:enable") + " to set up tunnel");
      process.exit(1);
    }
  } catch (error) {
    logger.error(`Failed to get tunnel URL: ${error.message}`);
    process.exit(1);
  }
}
async function showTunnelLogs(options) {
  try {
    const lines = parseInt(options.lines || "100", 10);
    if (options.follow) {
      logger.info("Following logs (press Ctrl+C to exit)...");
      logger.newline();
      await pangolinService.followLogs();
    } else {
      const logs = await pangolinService.getLogs(lines);
      if (logs.trim()) {
        console.log(logs);
      } else {
        logger.info("No logs available");
      }
    }
  } catch (error) {
    logger.error(`Failed to get logs: ${error.message}`);
    process.exit(1);
  }
}
async function listTunnels(options) {
  try {
    const tunnels = await pangolinService.listTunnels();
    if (options.json) {
      console.log(JSON.stringify(tunnels, null, 2));
      return;
    }
    if (tunnels.length === 0) {
      logger.info("No tunnels configured");
      return;
    }
    logger.header("ACTIVE TUNNELS");
    tunnels.forEach((t) => {
      const statusIcon = t.status === "active" ? chalk15.green("\u25CF") : chalk15.gray("\u25CB");
      const status = t.status === "active" ? chalk15.green("Active") : chalk15.gray("Inactive");
      logger.info(`${statusIcon} ${chalk15.bold(t.name)} (${status})`);
      logger.info(`   Local Port: ${chalk15.cyan(t.localPort)}`);
      if (t.remotePort) {
        logger.info(`   Remote Port: ${chalk15.cyan(t.remotePort)}`);
      }
      if (t.url) {
        logger.info(`   URL: ${chalk15.cyan.underline(t.url)}`);
      }
      logger.newline();
    });
  } catch (error) {
    logger.error(`Failed to list tunnels: ${error.message}`);
    process.exit(1);
  }
}
async function updateTunnelConfig(options) {
  try {
    const { addTunnel, removeTunnel } = options;
    if (!addTunnel && !removeTunnel) {
      logger.info("Use --add-tunnel name:port or --remove-tunnel name");
      return;
    }
    if (addTunnel) {
      const [name, portStr] = addTunnel.split(":");
      if (!name || !portStr) {
        logger.error("Invalid format. Use: name:port");
        process.exit(1);
      }
      const port = parseInt(portStr, 10);
      if (isNaN(port) || port < 1 || port > 65535) {
        logger.error("Invalid port number");
        process.exit(1);
      }
      const currentTunnels = await pangolinService.listTunnels();
      const newTunnels = [
        ...currentTunnels.map((t) => ({
          name: t.name,
          localPort: t.localPort,
          protocol: "tcp"
        })),
        { name, localPort: port, protocol: "tcp" }
      ];
      const success = pangolinService.updateConfig({
        tunnels: newTunnels
      });
      if (success) {
        logger.success(`Added tunnel: ${name} (port ${port})`);
        logger.info("Restart tunnel to apply: " + chalk15.cyan("hestia tunnel:restart"));
      } else {
        logger.error("Failed to add tunnel");
        process.exit(1);
      }
    }
    if (removeTunnel) {
      const currentTunnels = await pangolinService.listTunnels();
      const newTunnels = currentTunnels.filter((t) => t.name !== removeTunnel).map((t) => ({
        name: t.name,
        localPort: t.localPort,
        protocol: "tcp"
      }));
      const success = pangolinService.updateConfig({
        tunnels: newTunnels
      });
      if (success) {
        logger.success(`Removed tunnel: ${removeTunnel}`);
        logger.info("Restart tunnel to apply: " + chalk15.cyan("hestia tunnel:restart"));
      } else {
        logger.error("Failed to remove tunnel");
        process.exit(1);
      }
    }
  } catch (error) {
    logger.error(`Failed to update config: ${error.message}`);
    process.exit(1);
  }
}
async function restartTunnel() {
  try {
    await withSpinner(
      "Restarting tunnel service...",
      async () => pangolinService.restart(),
      "Tunnel service restarted"
    );
  } catch (error) {
    logger.error(`Failed to restart tunnel: ${error.message}`);
    process.exit(1);
  }
}
function formatTunnelStatus(status) {
  switch (status) {
    case "connected":
      return chalk15.green("Connected");
    case "connecting":
      return chalk15.yellow("Connecting...");
    case "disconnected":
      return chalk15.gray("Disconnected");
    case "error":
      return chalk15.red("Error");
    default:
      return chalk15.gray("Unknown");
  }
}
function formatDuration2(ms) {
  const seconds = Math.floor(ms / 1e3);
  const minutes = Math.floor(seconds / 60);
  const hours = Math.floor(minutes / 60);
  const days = Math.floor(hours / 24);
  if (days > 0) return `${days}d ${hours % 24}h`;
  if (hours > 0) return `${hours}h ${minutes % 60}m`;
  if (minutes > 0) return `${minutes}m ${seconds % 60}s`;
  return `${seconds}s`;
}
function formatBytes6(bytes) {
  const units = ["B", "KB", "MB", "GB", "TB"];
  let size = bytes;
  let unitIndex = 0;
  while (size >= 1024 && unitIndex < units.length - 1) {
    size /= 1024;
    unitIndex++;
  }
  return `${size.toFixed(1)} ${units[unitIndex]}`;
}
async function detectNetworkType2() {
  try {
    return "unknown";
  } catch {
    return "unknown";
  }
}
function generateSecureToken() {
  try {
    return randomBytes(32).toString("hex");
  } catch {
    return Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
  }
}

// src/commands/services.ts
init_esm_shims();
init_utils();
var categoryDisplay = {
  network: { name: "Network", icon: "\u{1F310}", color: "#3b82f6" },
  database: { name: "Database", icon: "\u{1F5C4}\uFE0F", color: "#10b981" },
  ui: { name: "UI", icon: "\u{1F3A8}", color: "#f59e0b" },
  ai: { name: "AI", icon: "\u{1F916}", color: "#8b5cf6" }
};
function formatStatus4(status) {
  const statusConfig = {
    "not-installed": { icon: "\u25CB", color: "#9ca3af" },
    "installed": { icon: "\u25D0", color: "#6b7280" },
    "enabled": { icon: "\u25C9", color: "#3b82f6" },
    "running": { icon: "\u25CF", color: "#10b981" },
    "stopped": { icon: "\u25CC", color: "#f59e0b" },
    "error": { icon: "\u2717", color: "#ef4444" }
  };
  const config = statusConfig[status];
  return chalk15.hex(config.color)(`${config.icon} ${status}`);
}
function formatCategory(category) {
  const display = categoryDisplay[category];
  return chalk15.hex(display.color)(`${display.icon} ${display.name}`);
}
function servicesCommand(program2) {
  const services = program2.command("services").description("Manage optional Hestia services").option("-j, --json", "Output as JSON").action(async (options) => {
    await listServices(options);
  });
  services.command("list").description("List all services with their status").option("-c, --category <cat>", "Filter by category (network|database|ui|ai)").option("-j, --json", "Output as JSON").option("-v, --verbose", "Show detailed information").action(async (options) => {
    await listServices(options);
  });
  services.command("available").alias("ls-available").description("Show available optional services").option("-c, --category <cat>", "Filter by category").option("-j, --json", "Output as JSON").action(async (options) => {
    await listAvailableServices(options);
  });
  services.command("install <name>").description("Install an optional service").option("-p, --port <port>", "Specify preferred port").option("-y, --yes", "Skip confirmation prompts").action(async (name, options) => {
    await installService(name, options);
  });
  services.command("remove <name>").alias("uninstall").description("Remove an installed service").option("-f, --force", "Force removal without confirmation").action(async (name, options) => {
    await removeService(name, options);
  });
  services.command("start <name>").description("Start a service").action(async (name) => {
    await startService(name);
  });
  services.command("stop <name>").description("Stop a service").action(async (name) => {
    await stopService(name);
  });
  services.command("status [name]").description("Show detailed status of a service or all services").option("-j, --json", "Output as JSON").option("-w, --watch", "Watch mode - continuously update").action(async (name, options) => {
    if (options.watch) {
      await watchStatus2(name);
    } else {
      await showStatus2(name, options);
    }
  });
  services.command("enable <name>").description("Enable a service to auto-start").action(async (name) => {
    await enableService(name);
  });
  services.command("disable <name>").description("Disable a service from auto-starting").action(async (name) => {
    await disableService(name);
  });
  services.command("configure <name>").description("Configure a service").option("-p, --port <ports...>", "Port mappings (e.g., http:8080 https:8443)").option("-e, --env <vars...>", "Environment variables (e.g., KEY=value)").option("-f, --file <path>", "Load configuration from file").action(async (name, options) => {
    await configureService(name, options);
  });
  services.command("logs <name>").description("Show service logs").option("-n, --lines <num>", "Number of lines to show", "100").option("-f, --follow", "Follow log output").action(async (name, options) => {
    await showLogs(name, options);
  });
}
async function listServices(options) {
  try {
    const allServices = getAllOptionalServices();
    const statuses = await serviceManager.getAllStatuses();
    if (options.json) {
      const data = allServices.map((service) => {
        const statusInfo = statuses.find((s) => s.service.name === service.name);
        return {
          name: service.name,
          displayName: service.displayName,
          category: service.category,
          description: service.description,
          status: statusInfo?.status.status || "not-installed",
          installed: statusInfo?.status.status !== "not-installed",
          enabled: statusInfo?.status.status === "running" || statusInfo?.status.status === "enabled",
          running: statusInfo?.status.status === "running",
          ports: service.ports
        };
      });
      console.log(JSON.stringify(data, null, 2));
      return;
    }
    const categories = options.category ? [options.category] : getServiceCategories();
    logger.header("HESTIA SERVICES");
    logger.newline();
    for (const category of categories) {
      const catDisplay = categoryDisplay[category];
      const services = getServicesByCategory(category);
      if (services.length === 0) continue;
      console.log(chalk15.hex(catDisplay.color)(`${catDisplay.icon} ${catDisplay.name}`));
      console.log(chalk15.hex(catDisplay.color)("\u2500".repeat(40)));
      const tableData = services.map((service) => {
        const statusInfo = statuses.find((s) => s.service.name === service.name);
        const status = statusInfo?.status.status || "not-installed";
        return {
          Name: chalk15.white(service.displayName),
          Status: formatStatus4(status),
          Port: service.defaultPort.toString(),
          Description: chalk15.gray(service.description.slice(0, 40) + (service.description.length > 40 ? "..." : ""))
        };
      });
      table(tableData);
      logger.newline();
    }
    const summary = await serviceManager.getServicesSummary();
    logger.info(`Total: ${allServices.length} services | Installed: ${summary.installed} | Enabled: ${summary.enabled} | Running: ${summary.running}`);
  } catch (error) {
    logger.error(`Failed to list services: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function listAvailableServices(options) {
  try {
    let services = getAllOptionalServices();
    if (options.category) {
      services = services.filter((s) => s.category === options.category);
    }
    const availableServices = [];
    for (const service of services) {
      const installed = await service.isInstalled();
      if (!installed) {
        availableServices.push(service);
      }
    }
    if (options.json) {
      console.log(JSON.stringify(availableServices.map((s) => ({
        name: s.name,
        displayName: s.displayName,
        category: s.category,
        description: s.description,
        ports: s.ports,
        dependencies: s.dependencies
      })), null, 2));
      return;
    }
    if (availableServices.length === 0) {
      logger.success("All optional services are already installed!");
      return;
    }
    logger.header("AVAILABLE OPTIONAL SERVICES");
    logger.newline();
    for (const service of availableServices) {
      console.log(`${formatCategory(service.category)} ${chalk15.bold.white(service.displayName)}`);
      console.log(chalk15.gray(service.description));
      if (service.ports.length > 0) {
        const ports = service.ports.map((p) => `${p.external} (${p.description})`).join(", ");
        console.log(chalk15.blue(`  Ports: ${ports}`));
      }
      if (service.dependencies.length > 0) {
        const deps = service.dependencies.map(
          (d) => `${d.name}${d.optional ? " (optional)" : ""}`
        ).join(", ");
        console.log(chalk15.yellow(`  Dependencies: ${deps}`));
      }
      logger.newline();
    }
    logger.info(`Use 'hestia services:install <name>' to install a service`);
  } catch (error) {
    logger.error(`Failed to list available services: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function installService(name, options) {
  try {
    if (!isValidService(name)) {
      logger.error(`Unknown service: ${name}`);
      logger.info(`Run 'hestia services:available' to see available services`);
      process.exit(1);
    }
    const service = getOptionalService(name);
    const installed = await service.isInstalled();
    if (installed) {
      logger.warn(`${service.displayName} is already installed`);
      return;
    }
    if (!options.yes) {
      const inquirer13 = (await import('inquirer')).default;
      const { confirm } = await inquirer13.prompt([{
        type: "confirm",
        name: "confirm",
        message: `Install ${service.displayName}?`,
        default: true
      }]);
      if (!confirm) {
        logger.info("Installation cancelled");
        return;
      }
    }
    await serviceManager.install(name);
  } catch (error) {
    logger.error(`Failed to install ${name}: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function removeService(name, options) {
  try {
    if (!isValidService(name)) {
      logger.error(`Unknown service: ${name}`);
      process.exit(1);
    }
    const service = getOptionalService(name);
    const installed = await service.isInstalled();
    if (!installed) {
      logger.warn(`${service.displayName} is not installed`);
      return;
    }
    if (!options.force) {
      const inquirer13 = (await import('inquirer')).default;
      const { confirm } = await inquirer13.prompt([{
        type: "confirm",
        name: "confirm",
        message: `Remove ${service.displayName}? This will delete all data associated with this service.`,
        default: false
      }]);
      if (!confirm) {
        logger.info("Removal cancelled");
        return;
      }
    }
    await serviceManager.remove(name);
  } catch (error) {
    logger.error(`Failed to remove ${name}: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function startService(name) {
  try {
    if (!isValidService(name)) {
      logger.error(`Unknown service: ${name}`);
      process.exit(1);
    }
    await serviceManager.start(name);
  } catch (error) {
    logger.error(`Failed to start ${name}: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function stopService(name) {
  try {
    if (!isValidService(name)) {
      logger.error(`Unknown service: ${name}`);
      process.exit(1);
    }
    await serviceManager.stop(name);
  } catch (error) {
    logger.error(`Failed to stop ${name}: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function showStatus2(name, options) {
  try {
    if (name) {
      if (!isValidService(name)) {
        logger.error(`Unknown service: ${name}`);
        process.exit(1);
      }
      const service = getOptionalService(name);
      const status = await serviceManager.getStatus(name);
      if (options.json) {
        console.log(JSON.stringify({
          name: service.name,
          displayName: service.displayName,
          category: service.category,
          ...status
        }, null, 2));
        return;
      }
      logger.header(`${service.displayName.toUpperCase()} STATUS`);
      logger.newline();
      console.log(`Status: ${formatStatus4(status.status)}`);
      if (status.version) console.log(`Version: ${chalk15.cyan(status.version)}`);
      if (status.url) console.log(`URL: ${chalk15.cyan(status.url)}`);
      if (status.uptime) console.log(`Uptime: ${chalk15.cyan(formatUptime3(status.uptime))}`);
      if (status.message) console.log(`Message: ${chalk15.gray(status.message)}`);
      if (status.lastError) console.log(`Last Error: ${chalk15.red(status.lastError)}`);
      if (status.ports && status.ports.length > 0) {
        logger.newline();
        console.log(chalk15.bold("Ports:"));
        for (const port of status.ports) {
          console.log(`  ${port.external}:${port.internal} (${port.description || "unknown"})`);
        }
      }
    } else {
      const statuses = await serviceManager.getAllStatuses();
      if (options.json) {
        console.log(JSON.stringify(statuses.map(({ service, status }) => ({
          name: service.name,
          displayName: service.displayName,
          category: service.category,
          ...status
        })), null, 2));
        return;
      }
      logger.header("SERVICES STATUS");
      logger.newline();
      const tableData = statuses.map(({ service, status }) => ({
        Service: service.displayName,
        Category: formatCategory(service.category),
        Status: formatStatus4(status.status),
        URL: status.url ? chalk15.cyan(status.url) : chalk15.gray("-")
      }));
      table(tableData);
    }
  } catch (error) {
    logger.error(`Failed to get status: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function watchStatus2(name, options) {
  const interval = 2e3;
  logger.info(`Watching status (press Ctrl+C to exit)...
`);
  const run = async () => {
    process.stdout.write("\x1Bc");
    await showStatus2(name, { json: false });
    logger.newline();
    logger.info(chalk15.gray(`Last updated: ${(/* @__PURE__ */ new Date()).toLocaleTimeString()}`));
    logger.info(chalk15.gray("Press Ctrl+C to exit"));
  };
  await run();
  const timer = setInterval(run, interval);
  process.on("SIGINT", () => {
    clearInterval(timer);
    logger.newline();
    logger.info("Stopped watching");
    process.exit(0);
  });
}
async function enableService(name) {
  try {
    if (!isValidService(name)) {
      logger.error(`Unknown service: ${name}`);
      process.exit(1);
    }
    await serviceManager.enable(name);
  } catch (error) {
    logger.error(`Failed to enable ${name}: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function disableService(name) {
  try {
    if (!isValidService(name)) {
      logger.error(`Unknown service: ${name}`);
      process.exit(1);
    }
    await serviceManager.disable(name);
  } catch (error) {
    logger.error(`Failed to disable ${name}: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function configureService(name, options) {
  try {
    if (!isValidService(name)) {
      logger.error(`Unknown service: ${name}`);
      process.exit(1);
    }
    const service = getOptionalService(name);
    const config = {};
    if (options.port) {
      const ports = {};
      for (const mapping of options.port) {
        const [key, value] = mapping.split(":");
        if (key && value) {
          ports[key] = parseInt(value, 10);
        }
      }
      config.ports = ports;
    }
    if (options.env) {
      const env = {};
      for (const variable of options.env) {
        const [key, value] = variable.split("=");
        if (key && value) {
          env[key] = value;
        }
      }
      config.environment = env;
    }
    if (options.file) {
      const fs25 = await import('fs/promises');
      const content = await fs25.readFile(options.file, "utf-8");
      const fileConfig = JSON.parse(content);
      Object.assign(config, fileConfig);
    }
    await serviceManager.configure(name, config);
  } catch (error) {
    logger.error(`Failed to configure ${name}: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
async function showLogs(name, options) {
  try {
    if (!isValidService(name)) {
      logger.error(`Unknown service: ${name}`);
      process.exit(1);
    }
    const lines = parseInt(options.lines || "100", 10);
    if (options.follow) {
      logger.info(`Following logs for ${name} (press Ctrl+C to exit)...
`);
      const { spawn: spawn12 } = await import('child_process');
      const target = process.env.HESTIA_TARGET || "/opt/hestia";
      const proc = spawn12("docker", [
        "compose",
        "-f",
        `${target}/docker-compose.yml`,
        "logs",
        "-f",
        "--tail",
        String(lines),
        name
      ], { cwd: target, stdio: "inherit" });
      process.on("SIGINT", () => {
        proc.kill();
        logger.newline();
        logger.info("Stopped following logs");
        process.exit(0);
      });
      return;
    }
    const logs = await serviceManager.getLogs(name, lines);
    console.log(logs);
  } catch (error) {
    logger.error(`Failed to get logs for ${name}: ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}
function formatUptime3(seconds) {
  const days = Math.floor(seconds / 86400);
  const hours = Math.floor(seconds % 86400 / 3600);
  const minutes = Math.floor(seconds % 3600 / 60);
  if (days > 0) return `${days}d ${hours}h ${minutes}m`;
  if (hours > 0) return `${hours}h ${minutes}m`;
  return `${minutes}m`;
}

